/**
 * Analytics data models for the dashboard feature.
 *
 * These types define the API surface for analytics queries.
 * The AnalyticsService returns these types; downstream agents
 * will implement the actual aggregation logic.
 */

import type { OrderStatus } from './order.js';

// ── Time range for all analytics queries ──────────────────────────

/**
 * Granularity for time-series data points.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Common query parameters for analytics endpoints.
 */
export interface AnalyticsQuery {
  /** Start of the time range (inclusive) */
  startDate: Date;
  /** End of the time range (inclusive) */
  endDate: Date;
  /** Granularity for time-series breakdown */
  granularity: TimeGranularity;
}

// ── Time-series data ──────────────────────────────────────────────

/**
 * A single data point in a time series.
 */
export interface TimeSeriesPoint {
  /** Start of this time bucket */
  timestamp: Date;
  /** Numeric value for this bucket */
  value: number;
}

/**
 * A named time series (e.g., "revenue", "orderCount").
 */
export interface TimeSeries {
  /** Metric identifier */
  metric: string;
  /** Ordered data points */
  points: TimeSeriesPoint[];
}

// ── Metric summaries ──────────────────────────────────────────────

/**
 * Supported metric types for the /metrics/:type endpoint.
 */
export type MetricType = 'revenue' | 'orders' | 'users' | 'average-order-value';

/**
 * Summary of a single metric with comparison to a prior period.
 */
export interface MetricSummary {
  /** Which metric this summarizes */
  type: MetricType;
  /** Current period value */
  currentValue: number;
  /** Previous period value (same duration, immediately preceding) */
  previousValue: number;
  /** Percentage change: ((current - previous) / previous) * 100 */
  changePercent: number;
  /** Time series for the current period */
  timeSeries: TimeSeries;
}

// ── Order analytics ───────────────────────────────────────────────

/**
 * Breakdown of orders by status.
 */
export interface OrderStatusBreakdown {
  status: OrderStatus;
  count: number;
  /** Total revenue for orders in this status */
  revenue: number;
}

// ── Dashboard (composite) ─────────────────────────────────────────

/**
 * Top-level dashboard response combining all summary data.
 * This is the primary response shape for GET /api/analytics/dashboard.
 */
export interface DashboardData {
  /** The query that produced this data */
  query: AnalyticsQuery;
  /** High-level KPI summaries */
  metrics: MetricSummary[];
  /** Order counts grouped by status */
  ordersByStatus: OrderStatusBreakdown[];
  /** Revenue time series for the queried period */
  revenueOverTime: TimeSeries;
  /** New-user time series for the queried period */
  newUsersOverTime: TimeSeries;
}

// ── Top-items helper ──────────────────────────────────────────────

/**
 * A product ranked by revenue or quantity sold.
 */
export interface TopProduct {
  productId: string;
  name: string;
  totalQuantity: number;
  totalRevenue: number;
}

/**
 * Analytics service — business logic for dashboard analytics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture notes:
 * - All methods accept an AnalyticsQuery to define the time window.
 * - Aggregation is computed on-the-fly from order/user data.
 * - Each public method maps to one analytics API operation.
 * - Stub implementations return placeholder data; downstream agents
 *   will fill in the real aggregation logic.
 *
 * Intended API surface (when an HTTP layer is added):
 *   GET /api/analytics/dashboard       → getDashboard()
 *   GET /api/analytics/metrics/:type   → getMetric()
 *   GET /api/analytics/top-products    → getTopProducts()
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  TopProduct,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard data for a time range.
   *
   * Combines all metric summaries, order-status breakdown,
   * and key time series into a single response.
   */
  getDashboard(query: AnalyticsQuery): DashboardData {
    this.logger.info(
      `Building dashboard: ${query.startDate.toISOString()} to ${query.endDate.toISOString()} (${query.granularity})`,
    );

    // TODO: Implement real aggregation over orderRepository / userRepository.
    // For now return placeholder structure so consumers can code against the shape.
    const emptyTimeSeries = { metric: 'placeholder', points: [] };

    return {
      query,
      metrics: [
        this.getMetric('revenue', query),
        this.getMetric('orders', query),
        this.getMetric('users', query),
        this.getMetric('average-order-value', query),
      ],
      ordersByStatus: [
        { status: 'pending', count: 0, revenue: 0 },
        { status: 'confirmed', count: 0, revenue: 0 },
        { status: 'shipped', count: 0, revenue: 0 },
        { status: 'delivered', count: 0, revenue: 0 },
        { status: 'cancelled', count: 0, revenue: 0 },
      ],
      revenueOverTime: { ...emptyTimeSeries, metric: 'revenue' },
      newUsersOverTime: { ...emptyTimeSeries, metric: 'newUsers' },
    };
  }

  /**
   * Get a single metric summary with period-over-period comparison.
   *
   * The "previous period" is the same duration immediately before startDate.
   * E.g., if the query spans 7 days, previousValue covers the 7 days before that.
   */
  getMetric(type: MetricType, query: AnalyticsQuery): MetricSummary {
    this.logger.info(`Computing metric: ${type}`);

    // TODO: Implement per-metric aggregation.
    // Downstream agent should:
    //  1. Filter orders/users within query.startDate–endDate
    //  2. Compute the current-period value
    //  3. Compute the previous-period value (same duration, shifted back)
    //  4. Build the time series at the requested granularity
    return {
      type,
      currentValue: 0,
      previousValue: 0,
      changePercent: 0,
      timeSeries: { metric: type, points: [] },
    };
  }

  /**
   * Get top products by revenue within a time range.
   *
   * @param query - Time range filter
   * @param limit - Max number of products to return (default 10)
   */
  getTopProducts(query: AnalyticsQuery, limit: number = 10): TopProduct[] {
    this.logger.info(`Computing top ${limit} products`);

    // TODO: Implement aggregation across order items.
    // Downstream agent should:
    //  1. Filter orders within the date range
    //  2. Flatten items, group by productId
    //  3. Sum quantity and revenue per product
    //  4. Sort by totalRevenue descending, take `limit`
    void query;
    void limit;
    return [];
  }
}

/**
 * Analytics repository — data access helpers for analytics aggregation.
 *
 * Unlike other repositories, AnalyticsRepository does NOT extend BaseRepository
 * because it doesn't manage its own collection. Instead, it reads from the
 * 'orders' and 'users' collections and provides aggregation-oriented queries.
 *
 * This separation keeps aggregation logic out of OrderRepository/UserRepository
 * while still going through the Database layer (respecting the repo pattern).
 */

import type { Database, DatabaseRecord } from '../utils/database.js';
import type { Order, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsRepository {
  private logger = new Logger('Repository:analytics');

  constructor(private db: Database) {}

  /**
   * Find all orders within a date range.
   *
   * TODO: Implement date filtering. Currently returns all orders.
   * Downstream agent should filter on order.createdAt.
   */
  findOrdersInRange(startDate: Date, endDate: Date): Order[] {
    this.logger.debug(
      `Finding orders in range: ${startDate.toISOString()} – ${endDate.toISOString()}`,
    );
    const records = this.db.findAll('orders');
    // TODO: Filter by createdAt within [startDate, endDate]
    return records.map((r) => this.toOrder(r));
  }

  /**
   * Find all users created within a date range.
   *
   * TODO: Implement date filtering. Currently returns all users.
   */
  findUsersCreatedInRange(startDate: Date, endDate: Date): User[] {
    this.logger.debug(
      `Finding users created in range: ${startDate.toISOString()} – ${endDate.toISOString()}`,
    );
    const records = this.db.findAll('users');
    // TODO: Filter by createdAt within [startDate, endDate]
    return records.map((r) => this.toUser(r));
  }

  /**
   * Count orders grouped by status.
   *
   * TODO: Optionally accept a date range filter.
   */
  countOrdersByStatus(): Record<OrderStatus, number> {
    const records = this.db.findAll('orders');
    const counts: Record<OrderStatus, number> = {
      pending: 0,
      confirmed: 0,
      shipped: 0,
      delivered: 0,
      cancelled: 0,
    };
    for (const r of records) {
      const status = r['status'] as OrderStatus;
      if (status in counts) {
        counts[status]++;
      }
    }
    return counts;
  }

  /**
   * Sum total revenue for orders in a given status.
   *
   * TODO: Optionally accept a date range filter.
   */
  sumRevenueByStatus(): Record<OrderStatus, number> {
    const records = this.db.findAll('orders');
    const revenue: Record<OrderStatus, number> = {
      pending: 0,
      confirmed: 0,
      shipped: 0,
      delivered: 0,
      cancelled: 0,
    };
    for (const r of records) {
      const status = r['status'] as OrderStatus;
      const total = r['total'] as number;
      if (status in revenue) {
        revenue[status] += total;
      }
    }
    return revenue;
  }

  // ── Record → Domain mappers ─────────────────────────────────────

  private toOrder(record: DatabaseRecord): Order {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      items: (record['items'] ?? []) as Order['items'],
      total: record['total'] as number,
      status: record['status'] as OrderStatus,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  private toUser(record: DatabaseRecord): User {
    return {
      id: record['id'] as string,
      name: record['name'] as string,
      email: record['email'] as string,
      role: record['role'] as User['role'],
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }
}

